SELECT 

WHERE pc.product_id = #{productId}
  AND pc.status = 1
  AND pc.delete_time IS NULL

    AND pc.score = #{score}

ORDER BY pc.create_time DESC, pc.id DESC

SELECT 

WHERE pc.product_id = #{productId}
  AND pc.status = 1
  AND pc.delete_time IS NULL
ORDER BY pc.create_time DESC, pc.id DESC
LIMIT #{limit}
